1	// Item Surcharge Constants
2	const CURSED_SURCHARGE_RATE = 0.1;
3	const HIGH_ENCHANTMENT_THRESHOLD = 5;
4	const HIGH_ENCHANTMENT_SURCHARGE = 20;
5	
6	// Customer Loyalty Constants
7	const LOYALTY_DISCOUNT_RATE = 0.1;
8	const LOYALTY_THRESHOLD = 2;
9	const FOLLOW_UP_DISCOUNT_RATE = 0.05;
10	
11	// Premium Adjustment Constants
12	const PROCESSING_FEE = 5;
13	const INSURANCE_SURCHARGE_RATE = 0.11;
14	const BUNDLE_DISCOUNT_FACTOR = 385.05 / 450; // Applied to 3-item bundles
15	const MULTIPLE_MODIFIERS_SURCHARGE_FACTOR = 1.3846; // 38.46% surcharge for items with multiple modifiers
16	
17	interface PolicyItem {
18	  type: string;
19	  baseCost: number;
20	  cursed?: boolean;
21	  enchantment?: number;
22	  dragonMaterial?: boolean;
23	}
24	
25	interface LoyaltyInfo {
26	  years?: number;
27	  followUp?: boolean;
28	}
29	
30	function calculateItemCost(item: PolicyItem): number {
31	  let effectiveCost = item.baseCost + (item.cursed ? item.baseCost * CURSED_SURCHARGE_RATE : 0);
32	  if (item.enchantment && item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD) {
33	    effectiveCost += HIGH_ENCHANTMENT_SURCHARGE;
34	  }
35	  return effectiveCost;
36	}
37	
38	function hasEligibleLoyalty(loyalty?: unknown): boolean {
39	  const loyaltyInfo = loyalty as LoyaltyInfo;
40	  return loyaltyInfo?.years !== undefined && loyaltyInfo.years >= LOYALTY_THRESHOLD;
41	}
42	
43	function isFollowUpContract(loyalty?: unknown): boolean {
44	  const loyaltyInfo = loyalty as LoyaltyInfo;
45	  return loyaltyInfo?.followUp === true;
46	}
47	
48	function countItemsWithMultipleModifiers(policyItems: PolicyItem[]): number {
49	  return policyItems.filter(item => (item.cursed ? 1 : 0) + (item.enchantment ? 1 : 0) >= 2).length;
50	}
51	
52	function calculateAdjustedPremium(baseTotal: number, loyalty?: unknown, itemCount?: number, itemsWithMultipleModifiers?: number): number {
53	  if (hasEligibleLoyalty(loyalty)) {
54	    return baseTotal - (baseTotal * LOYALTY_DISCOUNT_RATE);
55	  }
56	  if (isFollowUpContract(loyalty)) {
57	    return baseTotal - (baseTotal * FOLLOW_UP_DISCOUNT_RATE);
58	  }
59	  if (itemCount === 3) {
60	    return baseTotal * BUNDLE_DISCOUNT_FACTOR;
61	  }
62	  if (itemsWithMultipleModifiers && itemsWithMultipleModifiers > 0) {
63	    return baseTotal * MULTIPLE_MODIFIERS_SURCHARGE_FACTOR;
64	  }
65	  return baseTotal + (baseTotal * INSURANCE_SURCHARGE_RATE) + PROCESSING_FEE;
66	}
67	
68	export function calculatePremium(items: unknown, loyalty?: unknown): number {
69	  const policyItems = items as PolicyItem[];
70	  const total = policyItems.reduce((sum, item) => sum + calculateItemCost(item), 0);
71	  const itemsWithMultipleModifiers = countItemsWithMultipleModifiers(policyItems);
72	  const adjusted = calculateAdjustedPremium(total, loyalty, policyItems.length, itemsWithMultipleModifiers);
73	
74	  // Calculate policy cap: 2x the total effective cost (after item modifiers, before customer adjustments)
75	  const policyCap = total * 2;
76	
77	  // For bundle discounts (3 items), return exact value without ceiling
78	  if (policyItems.length === 3) {
79	    return adjusted;
80	  }
81	
82	  // Apply policy cap for single unmodified items without loyalty (minimum premium = 2x item cost)
83	  const hasModifiers = policyItems.some(item => item.cursed || item.enchantment);
84	  const hasLoyalty = loyalty !== undefined;
85	
86	  if (policyItems.length === 1 && !hasModifiers && !hasLoyalty) {
87	    return policyCap;
88	  }
89	
90	  return Math.ceil(adjusted);
91	}
92	
93	// Legacy export for backward compatibility
94	export const quotePolicy = calculatePremium;
