96	interface ClaimEntry {
97	  itemIndex: number;
98	  damageAmount: number;
99	}
100	
101	export function processClaim(policy: unknown, claims: unknown): number {
102	  const policyItems = policy as PolicyItem[];
103	  const claimEntries = claims as ClaimEntry[];
104	
105	  let totalReimbursement = 0;
106	  for (const claim of claimEntries) {
107	    const item = policyItems[claim.itemIndex];
108	    if (item.enchantment && item.enchantment >= 8) {
109	      totalReimbursement += claim.damageAmount * 0.5;
110	    }
111	  }
112	
113	  return totalReimbursement;
114	}
